]);

const lightTheme = EditorView.theme({
  '&': {
    height: '100%',
    fontSize: '12px',
  },
  '.cm-scroller': {
    fontFamily: "'Ubuntu Mono', 'Menlo', 'Monaco', 'Consolas', monospace",
    lineHeight: '1.5',
    overflow: 'auto',
  },
  '.cm-content': {
    caretColor: '#528bff',
    padding: '4px 0',
  },
  '.cm-gutters': {
    background: '#f5f5f5',
    borderRight: '1px solid #e0e0e0',
    color: '#999',
    minWidth: '32px',
  },
  '.cm-activeLineGutter': {
    background: '#e8f0fe',
  },
  '.cm-activeLine': {
    background: '#f0f4ff',
