274→      'postcss': path.resolve(__dirname, '../node_modules/postcss/lib/postcss.mjs'),
275→      'react-native-linear-gradient': path.resolve(__dirname, 'mocks/react-native-linear-gradient.tsx'),
276→      'react-native-modalize': path.resolve(__dirname, 'mocks/react-native-modalize.tsx'),
277→      'react-native-skeleton-placeholder': path.resolve(__dirname, 'mocks/react-native-skeleton-placeholder.tsx'),
278→      '@react-native-community/slider': path.resolve(__dirname, 'mocks/react-native-community-slider.tsx'),
279→      'lottie-react-native': path.resolve(__dirname, 'mocks/lottie-react-native.tsx'),
